import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getMyPayments } from '../../services/dataService';
import { formatDate, formatCurrency } from '../../utils/helpers';
import StatusBadge from '../../components/common/StatusBadge';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import { FiPlus } from 'react-icons/fi';

const CustomerPayments = () => {
  const [payments, setPayments] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetch = async () => {
      try {
        const res = await getMyPayments();
        setPayments(res.data.data);
      } catch (err) { console.error(err); }
      finally { setLoading(false); }
    };
    fetch();
  }, []);

  const totalVerified = payments.filter(p => p.status === 'verified').reduce((sum, p) => sum + p.amount, 0);
  const totalPending = payments.filter(p => p.status === 'pending').reduce((sum, p) => sum + p.amount, 0);

  if (loading) return <LoadingSpinner />;

  return (
    <div>
      <div className="page-header">
        <h1>My Payments</h1>
        <Link to="/customer/payments/new" className="btn btn-primary"><FiPlus /> Make Payment</Link>
      </div>

      <div className="stats-grid" style={{ marginBottom: '24px' }}>
        <div className="stat-card"><div className="stat-value">{formatCurrency(totalVerified)}</div><div className="stat-label">Total Verified</div></div>
        <div className="stat-card"><div className="stat-value">{formatCurrency(totalPending)}</div><div className="stat-label">Pending Verification</div></div>
        <div className="stat-card"><div className="stat-value">{payments.length}</div><div className="stat-label">Total Payments</div></div>
      </div>

      {payments.length === 0 ? (
        <div className="empty-state"><p>No payments made yet</p></div>
      ) : (
        <div className="table-container">
          <table>
            <thead><tr><th>Property</th><th>Amount</th><th>Method</th><th>Reference</th><th>Status</th><th>Date</th><th>Remarks</th></tr></thead>
            <tbody>
              {payments.map(p => (
                <tr key={p._id}>
                  <td>{p.property?.title || 'N/A'}</td>
                  <td>{formatCurrency(p.amount)}</td>
                  <td>{p.paymentMethod?.replace('_', ' ')}</td>
                  <td>{p.transactionReference || '-'}</td>
                  <td><StatusBadge status={p.status} /></td>
                  <td>{formatDate(p.createdAt)}</td>
                  <td>{p.adminRemarks || '-'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default CustomerPayments;
